module top_module(
out     ,  
enable  ,  
clk     ,  
reset      
);output [7:0] out;

     input enable, clk, reset;

    reg [7:0] out;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
if (reset) begin
  out <= 8'b0 ;
end else if (enable) begin
  out <= out + 1;
end


endmodule
